from fractions import Fraction

# Represent values as (p, q) meaning p + q*sqrt(3)
# where p, q are Fractions

def add(a, b):
    return (a[0]+b[0], a[1]+b[1])

def neg(a):
    return (-a[0], -a[1])

def mul(a, b):
    # (p1+q1*s)(p2+q2*s) = (p1*p2 + 3*q1*q2) + (p1*q2+q1*p2)*s
    return (a[0]*b[0] + 3*a[1]*b[1], a[0]*b[1] + a[1]*b[0])

def inv(a):
    # 1/(p+q*s) = (p-q*s)/(p²-3q²)
    denom = a[0]*a[0] - 3*a[1]*a[1]
    if denom == 0:
        raise ValueError(f"Division by zero: {a}")
    return (a[0]/denom, -a[1]/denom)

def div(a, b):
    return mul(a, inv(b))

def sub(a, b):
    return add(a, neg(b))

ONE = (Fraction(1), Fraction(0))
ZERO = (Fraction(0), Fraction(0))

# a(1) = 1, a(2) = 1/sqrt(3) = sqrt(3)/3
a = [None, (Fraction(1), Fraction(0)), (Fraction(0), Fraction(1,3))]

for n in range(1, 25):
    an = a[n]
    an1 = a[n+1]
    # a(n+2) = (a(n) + a(n+1)) / (1 - a(n)*a(n+1))
    num = add(an, an1)
    prod = mul(an, an1)
    denom = sub(ONE, prod)
    an2 = div(num, denom)
    a.append(an2)

for i in range(1, 27):
    p, q = a[i]
    val_str = f"{p}" if q == 0 else f"{p} + {q}*s" if p != 0 else f"{q}*s"
    print(f"a({i}) = {val_str}")

print()
print(f"a(5) = {a[5]}")
print(f"a(17) = {a[17]}")
print(f"a(25) = {a[25]}")
print(f"a(26) = {a[26]}")
print(f"a(25) == a(1): {a[25] == a[1]}")
print(f"a(26) == a(2): {a[26] == a[2]}")
PYEOF
